item.command:
/bin/bash -lc "python3 - <<'PY'
import json, urllib.request
vulns=json.load(open('/tmp/osv-vulns-all.json'))
ids=sorted({vid for r in vulns for vid in r['vulns']})
for vid in ids:
    req=urllib.request.Request('https://api.osv.dev/v1/vulns/'+vid)
    with urllib.request.urlopen(req, timeout=30) as resp: data=json.load(resp)
    fixed=[]
    for aff in data.get('affected',[]):
        pkg=aff.get('package',{}).get('name')
        for rng in aff.get('ranges',[]):
            for ev in rng.get('events',[]):
                if 'fixed' in ev: fixed.append((pkg,ev['fixed']))
    print(vid, data.get('summary','')[:120], 'FIXED', fixed[:10])
PY"

/bin/bash -lc "python3 - <<'PY'
import json, urllib.request
