PY"

/bin/bash -lc "python3 - <<'PY'
import json, urllib.request
candidates={
'com.fasterxml.jackson.core:jackson-databind':['2.18.8','2.19.4','2.20.1','2.21.4'],
'org.bouncycastle:bcprov-jdk15on':['1.84','1.85'],
'software.amazon.ion:ion-java':['1.10.5','1.11.10']
}
queries=[]; labels=[]
for k,vs in candidates.items():
  for v in vs:
    labels.append((k,v)); queries.append({\"package\":{\"ecosystem\":\"Maven\",\"name\":k},\"version\":v})
req=urllib.request.Request('https://api.osv.dev/v1/querybatch',data=json.dumps({'queries':queries}).encode(),headers={'Content-Type':'application/json'})
with urllib.request.urlopen(req,timeout=60) as r: data=json.load(r)
for (k,v),res in zip(labels,data['results']): print(k,v,[x['id'] for x in res.get('vulns') or []])
PY"

